import{_ as t,c as a,o as i,ax as n}from"./chunks/framework.DHqKNX4U.js";const g=JSON.parse('{"title":"Search Indexing & Reindexing","description":"","frontmatter":{},"headers":[],"relativePath":"user-guides/search-indexing.md","filePath":"user-guides/search-indexing.md"}'),r={name:"user-guides/search-indexing.md"};function s(o,e,d,h,l,c){return i(),a("div",null,e[0]||(e[0]=[n('<h1 id="search-indexing-reindexing" tabindex="-1">Search Indexing &amp; Reindexing <a class="header-anchor" href="#search-indexing-reindexing" aria-label="Permalink to &quot;Search Indexing &amp; Reindexing&quot;">​</a></h1><p>Open Archiver stores every archived email in two places: the <strong>database and file storage</strong> are the source of truth, while <strong>Meilisearch</strong> holds a secondary, full-text <strong>search index</strong>. When you search, you are querying Meilisearch. If a message is in the archive but missing from the index, it will not appear in search results until it is (re)indexed.</p><p>This guide explains how indexing stays reliable, how to see index coverage, and how to repair gaps.</p><h2 id="how-indexing-works" tabindex="-1">How indexing works <a class="header-anchor" href="#how-indexing-works" aria-label="Permalink to &quot;How indexing works&quot;">​</a></h2><ul><li>When emails are ingested (initial import or continuous sync), they are written to the archive and then queued for indexing on the <strong><code>indexing</code></strong> job queue.</li><li>Each batch is only marked as indexed <strong>after Meilisearch confirms</strong> the write succeeded. If Meilisearch rejects or drops a batch, the job fails and is retried automatically — it is never silently reported as done.</li><li>Because the index is a <em>secondary</em> store, it can always be rebuilt from the archive. Rebuilding is safe and idempotent: Meilisearch documents are keyed by the email ID, so re-indexing an email <strong>updates</strong> its document rather than creating a duplicate.</li></ul><h2 id="index-health" tabindex="-1">Index health <a class="header-anchor" href="#index-health" aria-label="Permalink to &quot;Index health&quot;">​</a></h2><p>Every ingestion source shows an <strong>index-health</strong> figure — &quot;<em>X of Y emails indexed</em>&quot; — comparing the number of archived emails (database) against the number of documents in the search index (Meilisearch). You can see it:</p><ul><li>On the <strong>Ingestion Sources</strong> list (in the status hover card).</li><li>On a source&#39;s <strong>Statistics</strong> page (see below), as an index-coverage bar.</li><li>Globally on the dashboard via the <a href="/api/dashboard.html#get-index-health">index-health endpoint</a>.</li></ul><p>A gap between the two numbers means some emails are missing from search and should be reindexed.</p><h2 id="automatic-self-healing" tabindex="-1">Automatic self-healing <a class="header-anchor" href="#automatic-self-healing" aria-label="Permalink to &quot;Automatic self-healing&quot;">​</a></h2><p>A background <strong>reconcile</strong> job runs on a schedule and re-queues any emails that are archived but not yet in the index, so transient failures heal on their own without any action. It is safe to leave on and is designed to stay cheap even with millions of emails.</p><p>It is controlled by environment variables:</p><table tabindex="0"><thead><tr><th>Variable</th><th>Default</th><th>Purpose</th></tr></thead><tbody><tr><td><code>INDEX_RECONCILE_ENABLED</code></td><td><code>true</code></td><td>Enable/disable the periodic reconcile job.</td></tr><tr><td><code>INDEX_RECONCILE_CRON</code></td><td><code>*/30 * * * *</code></td><td>How often reconcile runs (cron pattern).</td></tr><tr><td><code>INDEX_RECONCILE_PAGE_CAP</code></td><td><code>20</code></td><td>Max batches enqueued per run, so a large backlog drains over several runs.</td></tr><tr><td><code>INDEX_RECONCILE_BACKPRESSURE</code></td><td><code>100</code></td><td>If the indexing queue already has this many jobs, the run defers.</td></tr><tr><td><code>MAX_INDEX_ATTEMPTS</code></td><td><code>5</code></td><td>Stop retrying an email after this many failed indexing attempts (prevents a single bad email from looping forever).</td></tr><tr><td><code>MEILI_WAIT_FOR_TASK_TIMEOUT</code></td><td><code>300000</code></td><td>Milliseconds to wait for a Meilisearch task before treating the batch as failed.</td></tr></tbody></table><h2 id="reindexing" tabindex="-1">Reindexing <a class="header-anchor" href="#reindexing" aria-label="Permalink to &quot;Reindexing&quot;">​</a></h2><p>Reindexing rebuilds search documents from the archive. It never re-downloads mail and never duplicates data. There are two modes:</p><ul><li><strong>Missing</strong> (default) — only (re)indexes emails that are not currently in the index. Cheap; use this to fill gaps.</li><li><strong>Full</strong> — resets and rebuilds every document for the selected scope. Use this after a search-schema change, or when you suspect the index is stale even though emails appear &quot;indexed&quot;.</li></ul><h3 id="reindex-a-single-source" tabindex="-1">Reindex a single source <a class="header-anchor" href="#reindex-a-single-source" aria-label="Permalink to &quot;Reindex a single source&quot;">​</a></h3><p>On the <strong>Ingestion Sources</strong> page, open a source&#39;s actions menu and choose <strong>Reindex</strong>. This reindexes the source and its entire merge group (missing mode). For a full rebuild of one source, call the API with <code>{&quot;mode&quot;: &quot;full&quot;}</code> — see <a href="/api/ingestion.html#reindex-an-ingestion-source">Reindex an Ingestion Source</a>.</p><h3 id="reindex-everything" tabindex="-1">Reindex everything <a class="header-anchor" href="#reindex-everything" aria-label="Permalink to &quot;Reindex everything&quot;">​</a></h3><p>Use the <strong>Reindex All</strong> button at the top of the Ingestion Sources page and pick <strong>Reindex missing</strong> or <strong>Full rebuild</strong>. This covers every source. See <a href="/api/ingestion.html#reindex-all-sources">Reindex All Sources</a>.</p><div class="tip custom-block"><p class="custom-block-title">Upgrading from an older version</p><p>On upgrade, existing emails are marked as indexed to avoid re-indexing the whole archive automatically. If the index-health figure shows a genuine gap for older data, run a <strong>Full rebuild</strong> (or a per-source full reindex) once to bring the index up to date.</p></div><h3 id="watching-progress" tabindex="-1">Watching progress <a class="header-anchor" href="#watching-progress" aria-label="Permalink to &quot;Watching progress&quot;">​</a></h3><p>Reindexing enqueues batches onto the <code>indexing</code> queue. You can watch them drain in <strong>Admin → Jobs</strong> (the <code>indexing</code> queue), and the index-health figure will climb as batches complete. If jobs pile up in <em>waiting</em> and never move, make sure the <strong>indexing worker</strong> process is running.</p><h2 id="per-source-statistics" tabindex="-1">Per-source statistics <a class="header-anchor" href="#per-source-statistics" aria-label="Permalink to &quot;Per-source statistics&quot;">​</a></h2><p>Each ingestion source has a <strong>View statistics</strong> action (in the row menu) that opens a read-only page with total emails, mailboxes, storage usage (email + attachment), attachments, threads, date range, index coverage, a per-mailbox breakdown, merge-group children, and a recent-activity chart. See the <a href="/api/ingestion.html#get-statistics">statistics endpoint</a>.</p><h2 id="search-index-administration" tabindex="-1">Search-index administration <a class="header-anchor" href="#search-index-administration" aria-label="Permalink to &quot;Search-index administration&quot;">​</a></h2><p>For deeper troubleshooting, <strong>Admin → Index</strong> (Super Administrator only) mirrors the essential parts of the Meilisearch dashboard directly inside Open Archiver:</p><ul><li><strong>Instance overview</strong> — host, version, health, and database size.</li><li><strong>Index metadata</strong> — document count, primary key, indexing state, and field distribution for the <code>emails</code> index.</li><li><strong>Documents by ingestion source</strong> — per-source document counts taken straight from the search index (not the database), which is the quickest way to spot which source is under-indexed.</li><li><strong>Tasks</strong> — the Meilisearch task list (additions, settings updates, etc.) with status, received/indexed document counts, duration, timestamps, and error details for failed tasks, plus status filtering and pagination.</li></ul><p>These screens are backed by the read-only <a href="/api/index-admin.html">Index Admin API</a>.</p>',29)]))}const m=t(r,[["render",s]]);export{g as __pageData,m as default};
